export declare const mcpRoutesTemplate = "import { NextResponse } from \"next/server\";\nimport {\n  searchDocs,\n  ensureDocsIndex,\n  getIndexStatus,\n  DOCS_TOOLS,\n  listDocs,\n  getDoc,\n} from \"@/services/mcp\";\nimport type { MCPToolName } from \"@/services/mcp\";\n\ninterface ToolCallRequest {\n  tool: MCPToolName;\n  params: Record<string, unknown>;\n}\n\nexport async function POST(req: Request) {\n  try {\n    const { tool, params } = (await req.json()) as ToolCallRequest;\n\n    if (!tool) {\n      return NextResponse.json(\n        { error: \"Missing 'tool' parameter\" },\n        { status: 400 },\n      );\n    }\n\n    switch (tool) {\n      case \"search_docs\": {\n        const query = String(params?.query || \"\");\n        const limit = typeof params?.limit === \"number\" ? params.limit : 6;\n        await ensureDocsIndex();\n        const results = await searchDocs(query, limit);\n        return NextResponse.json({\n          content: results.map(({ chunk, score }) => ({\n            path: chunk.path,\n            uri: chunk.uri,\n            score: score.toFixed(3),\n            text: chunk.text,\n          })),\n        });\n      }\n\n      case \"get_doc\": {\n        const path = String(params?.path || \"\");\n        const doc = await getDoc({ path });\n        if (!doc) {\n          return NextResponse.json(\n            { error: \"Document not found\" },\n            { status: 404 },\n          );\n        }\n        return NextResponse.json({ content: doc });\n      }\n\n      case \"list_docs\": {\n        const directory =\n          typeof params?.directory === \"string\" ? params.directory : undefined;\n        const docs = await listDocs({ directory });\n        return NextResponse.json({\n          content: docs.map((d) => ({\n            name: d.name,\n            path: d.path,\n            uri: d.uri,\n          })),\n        });\n      }\n\n      default:\n        return NextResponse.json(\n          { error: `Unknown tool: ${tool}` },\n          { status: 400 },\n        );\n    }\n  } catch (e: unknown) {\n    const message = e instanceof Error ? e.message : \"Unknown error\";\n    return NextResponse.json({ error: message }, { status: 500 });\n  }\n}\n\nexport async function GET() {\n  const status = getIndexStatus();\n  return NextResponse.json({\n    tools: DOCS_TOOLS,\n    index: {\n      ready: status.ready,\n      chunkCount: status.chunkCount,\n    },\n  });\n}";
